const input = $input.first().json;
const body = input.body || input;
const title = (body.title || '').trim();
const content = (body.content || '').trim();

if (!title || !content) {
  return [{ json: { valid: false, error: 'Missing required fields: title and content' } }];
}

return [{
  json: {
    valid: true,
    title: title,
    url: (body.url || '').trim(),
    source_type: (body.source_type || 'blog_post').trim(),
    original_content: content.substring(0, 5000)
  }
}];

const input = $input.first().json;
try {
  if (input.error || (input.statusCode && input.statusCode >= 400)) throw new Error(input.error || 'HTTP ' + input.statusCode);
  const content = input.choices?.[0]?.message?.content;
  if (!content) throw new Error('No content');
  const data = JSON.parse(content.replace(/```json\n?|```\n?/g, '').trim());
  return [{ json: { platform: 'linkedin', success: true, parsed_content: data, draft_text: data.text } }];
} catch (err) {
  return [{ json: { platform: 'linkedin', success: false, error: err.message, draft_text: '', parsed_content: null } }];
}

