  return [{ json: { platform: 'email_newsletter', success: false, error: err.message, draft_text: '', parsed_content: null } }];
}

const linkedin = $('Parse LinkedIn').first().json;
const twitter = $('Parse Twitter').first().json;
const email = $('Parse Email').first().json;
const contentId = $('Store Content').first().json.id;

const drafts = [linkedin, twitter, email];
const esc = (s) => String(s || '').replace(/'/g, "''");

const values = drafts.map(d => {
  const pc = JSON.stringify(d.parsed_content || {}).replace(/'/g, "''");
  const status = d.success ? 'draft' : 'failed';
  return `(${contentId}, '${esc(d.platform)}', '${esc(d.draft_text)}', '${pc}'::jsonb, '${status}')`;
}).join(',\n');

return [{ json: { contentId, sql: `INSERT INTO content_drafts (content_id, platform, draft_text, parsed_content, status) VALUES\n${values}`, drafts } }];

const drafts = $('Store Drafts').first().json.drafts;
const contentId = $('Store Content').first().json.id;

return [{
  json: {
    status: 'drafts_generated',
    content_id: contentId,
    platforms: {
      linkedin: drafts.find(d => d.platform === 'linkedin')?.success || false,
      twitter: drafts.find(d => d.platform === 'twitter')?.success || false,
      email_newsletter: drafts.find(d => d.platform === 'email_newsletter')?.success || false
    },
    drafts: drafts.map(d => ({
      platform: d.platform,
      success: d.success,
      preview: (d.draft_text || '').substring(0, 100) + '...'
    }))
  }
}];
